export const DoubleClickToEdit: Story = {
  name: "Double click to edit",
  args: {
    columns: columns,
    data: productsGenerator(),
    sourceCode: `\
    import BootstrapTable from 'react-bootstrap-table-ng';
    import cellEditFactory from 'react-bootstrap-table-ng-editor';

    const columns = [{
