function beforeSaveCell(oldValue: any, newValue: any, row: any, column: any, done: any) {
  setTimeout(() => {
    // eslint-disable-next-line no-restricted-globals
    if (confirm('Do you want to accep this change?')) {
      done(true);
    } else {
      done(false);
    }
  }, 0);
  return { async: true };
}

