    sourceCode: `\
    import BootstrapTable from 'react-bootstrap-table-ng';
    import cellEditFactory from 'react-bootstrap-table-ng-editor';

    interface QualityRangerProps {
      value?: number;
      onUpdate: (value: number) => void;
      didMount?: () => void;
    }

    const QualityRanger = ({ value = 0, onUpdate, ...rest }: QualityRangerProps) => {
      const rangeRef = React.useRef<HTMLInputElement>(null);

      const getValue = () => {
        return parseInt(rangeRef.current?.value || '0', 10);
      };

      return [
        <input
          { ...rest }
          key="range"
          ref={ rangeRef }
          type="range"
          min="0"
          max="100"
        />,
        <button
          key="submit"
          className="btn btn-default"
          onClick={ () => onUpdate(getValue()) }
        >
          done
        </button>
      ];
    };

    const columns = [{
      dataField: 'id',
      text: 'Product ID'
    }, {
      dataField: 'name',
      text: 'Product Name'
    }, {
      dataField: 'quality',
      text: 'Product Quality',
      editorRenderer: (editorProps, value, row, column, rowIndex, columnIndex) => (
        <QualityRanger { ...editorProps } value={ value } />
      )
    }];

    <BootstrapTable
      keyField="id"
      data={ products }
      columns={ columns }
      cellEdit={ cellEditFactory({ mode: 'click', blurToSave: true }) }
    />
    `,
    cellEdit: cellEditFactory({ mode: 'click', blurToSave: true }),
